// Determine posting day and post type rotation
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const dayName = dayNames[now.getDay()];

// Post type rotation: Mon=insight, Wed=educational, Fri=engagement
const postTypeByDay = {
  monday: 'insight',
  wednesday: 'educational',
  friday: 'engagement'
};
const todayPostType = postTypeByDay[dayName] || 'insight';

const postTypeDescriptions = {
  insight: 'Industry commentary or opinion on a compliance/cyber/defence supply chain trend. Take a clear position. Reference real regulation changes, DEFCON 658 deadlines, or market shifts.',
  educational: 'How-to or explainer about Cyber Essentials, DCC (Defence Cyber Compliance), Def Stan 05-138, ISO 27001, or SOC 2 processes. Practical, actionable advice for SME leaders.',
  engagement: 'Question, discussion prompt, or defence supply chain challenge. Invite the audience to share their experience. Focus on pain points SMEs actually face.'
};

// Idempotency check
const idempotencyKey = `linkedin-post:${dateStr}`;

// Build the system prompt with full Meshwork brand context
const systemPrompt = `You are a senior LinkedIn content strategist for Meshwork, a multi-framework compliance platform for UK SMEs.

## Brand Context
- Product: Meshwork - Multi-framework compliance platform
- Target audience: UK SMEs (10-100 employees) in the defence supply chain, plus IT/compliance decision-makers
- Frameworks covered: Def Stan 05-138, ISO 27001, SOC 2, IASME Governance, Cyber Essentials, DCC (Levels 0-3)
- Key stats: 410+ controls mapped across frameworks, 70% evidence reuse between frameworks
- DEFCON 658 deadline makes Defence Cyber Compliance (DCC) mandatory for MOD suppliers
- Brand voice: Clear, confident, warm, action-oriented. Practitioner tone, NOT vendor marketing.
- ALWAYS use UK spelling (defence, organisation, behaviour, recognise, etc.)

## LinkedIn Post Rules
- 150-250 words per post
- 3-5 relevant hashtags at the end
- Strong hook in the first 2 lines (this is what shows before "see more")
- NEVER open with generic phrases like "Excited to share", "Thrilled to announce", "In today's world"
- Write as a thought leader who works in compliance daily, not as a software vendor
- Include a clear call-to-action or question to drive engagement
- Use line breaks for readability (LinkedIn rewards scannable content)
- Reference specific regulations, deadlines, or real industry events where possible`;

const userPrompt = `Generate 3 LinkedIn post options for today.

**Date**: ${dayName.charAt(0).toUpperCase() + dayName.slice(1)}, ${dateStr}
**Primary post type**: ${todayPostType}

Create exactly 3 post options:

**Option 1 (${todayPostType} - PRIMARY):**
${postTypeDescriptions[todayPostType]}

**Option 2 (${todayPostType === 'insight' ? 'educational' : todayPostType === 'educational' ? 'engagement' : 'insight'}):**
${postTypeDescriptions[todayPostType === 'insight' ? 'educational' : todayPostType === 'educational' ? 'engagement' : 'insight']}

**Option 3 (${todayPostType === 'insight' ? 'engagement' : todayPostType === 'educational' ? 'insight' : 'educational'}):**
${postTypeDescriptions[todayPostType === 'insight' ? 'engagement' : todayPostType === 'educational' ? 'insight' : 'educational']}

Format each option with:
- A clear "OPTION 1/2/3" header with the post type in brackets
- The full post text ready to copy-paste to LinkedIn
- Hashtags on a separate final line

Make each post distinct in topic and angle. Avoid repeating the same talking points across options.`;

return [{
  json: {
    dateStr,
    dayName,
    todayPostType,
    idempotencyKey,
    systemPrompt,
    userPrompt
  }
}];

// Parse the GLM-5 response and format the 3 post options
const response = $input.item.json;
const dateStr = $('Build Post Generation Prompt').item.json.dateStr;
const dayName = $('Build Post Generation Prompt').item.json.dayName;
const todayPostType = $('Build Post Generation Prompt').item.json.todayPostType;

// Extract text from Anthropic Messages API response
let postContent = '';
if (response.content && Array.isArray(response.content)) {
  postContent = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response === 'string') {
  postContent = response;
}

// Track token usage
const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

// Format notification text
const notificationText = `*LinkedIn Post Drafts Ready* (${dayName.charAt(0).toUpperCase() + dayName.slice(1)}, ${dateStr})\n\nPrimary type: ${todayPostType}\nTokens used: ${inputTokens} in / ${outputTokens} out\n\n${postContent.substring(0, 2000)}${postContent.length > 2000 ? '\n\n_[Truncated - see full output in thread]_' : ''}`;

return [{
  json: {
    dateStr,
    dayName,
    todayPostType,
    postContent,
    inputTokens,
    outputTokens,
    notificationText
  }
}];
